mapper.select:
SELECT

FROM sys_log a
WHERE id = #{id}

SELECT
FROM sys_log a LEFT JOIN sys_user u ON u.id = a.user_id
AND a.type = #{queryType}
AND a.remote_addr = #{queryRemoteAddr}
AND u.login_name LIKE CONCAT('%', #{queryUserLoginName}, '%')
AND u.name LIKE CONCAT('%', #{queryUserName}, '%')
AND a.title LIKE CONCAT('%', #{queryTitle}, '%')
AND a.request_uri LIKE CONCAT('%', #{queryRequestUri}, '%')
AND a.log_date BETWEEN #{queryBeginDate} AND #{queryEndDate}
ORDER BY a.log_date DESC

